descriptor.templateCss:
.rpc-container {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 16px;
  box-sizing: border-box;
  background: #ffffff;
  justify-content: center;
}

.input-row {
  display: flex;
  align-items: center;
  gap: 12px;
  width: 100%;
}

.input-field {
  flex: 1;
}

.send-button {
  height: 52px;
  margin-bottom: 4px; 
}

.status-badge {
  font-size: 13px;
  font-weight: 500;
  padding: 6px 12px;
  border-radius: 4px;
  text-align: center;
  max-width: fit-content;
}

.status-idle { background: #f2f4f7; color: #667085; }
.status-executing { background: #eff8ff; color: #175cd3; }
.status-success { background: #e8f5e9; color: #2e7d32; }
.status-error { background: #ffebee; color: #c62828; }

descriptor.controllerScript:
let settings;

self.onInit = function() {
    let utils = self.ctx.$scope.$injector.get(self.ctx.servicesMap.get('utils'));
    settings = utils.deepClone(self.ctx.settings) || {};
    
    // Variables de configuración e interfaz vinculadas al scope de Angular
    self.ctx.$scope.label = settings.inputLabel || 'Ingrese valor (Float)';
    self.ctx.$scope.executing = false;
    self.ctx.$scope.statusText = '';
    self.ctx.$scope.statusClass = 'status-idle';
    
    // Inicialización del control del formulario reactivo con valor por defecto 0.0
    self.ctx.$scope.valueControl = self.ctx.$scope.fb.control(0.0);
    
    // Función encargada del envío RPC
    self.ctx.$scope.sendValue = function() {
        let method = settings.rpcMethod || 'setFloatValue';
        let timeout = settings.rpcTimeout || 5000;
        
        // El input entrega el valor numérico directamente (mantiene decimales)
        let floatValue = self.ctx.$scope.valueControl.value;
        let params = { value: floatValue };
        
        // Bloqueo de UI y estado "Enviando"
        self.ctx.$scope.executing = true;
        self.ctx.$scope.statusText = 'Enviando comando...';
        self.ctx.$scope.statusClass = 'status-executing';
        self.ctx.detectChanges();
        
        // Ejecución del RPC Two-Way hacia la plataforma
        self.ctx.controlApi.sendTwoWayCommand(method, params, timeout).subscribe(
            function(response) {
                self.ctx.$scope.executing = false;
                self.ctx.$scope.statusText = 'Comando recibido con éxito.';
                self.ctx.$scope.statusClass = 'status-success';
                self.ctx.controlApi.completedCommand();
                self.ctx.detectChanges();
                clearStatus();
            },
            function(err) {
                self.ctx.$scope.executing = false;
                self.ctx.$scope.statusText = err.error?.message || 'Error: Sin respuesta del dispositivo.';
                self.ctx.$scope.statusClass = 'status-error';
                self.ctx.detectChanges();
                clearStatus();
            }
        );
    };
    
    // Función para limpiar la caja de estado pasados unos segundos
    function clearStatus() {
        setTimeout(function() {
            self.ctx.$scope.statusText = '';
            self.ctx.$scope.statusClass = 'status-idle';
            self.ctx.detectChanges();
        }, 4000);
    }
};

self.typeParameters = function() {
    return {
        singleEntity: true,
        dataKeysOptional: true
    };
};
